void solve(int CASE)
{
	string s; cin >> s;
	int n = s.size();
	s = ' ' + s;
	var pre = vector<int>(n + 1);
	fa(i, 1, n)pre[i] = pre[i - 1] + (s[i] == '0' ? -1 : 1);

	if (pre[n]) {
		cout << "-1" << endl;
		return;
	}

	var stmx = ST<int>(pre, ST<int>::_max);
	var stmn = ST<int>(pre, ST<int>::_min);
	var ans = vector<pii>();
	int now = 1;
	var dfs = [&](var dfs, int L, int R)->void {
		if (R - L + 1 < 2)return;
		if (s[L] == '0') {
			ans.pb({ now,1 });
			int l = L, r = R, res = 0;
			while (l <= r) {
				int mid = l + r >> 1;
				if (stmx.queryMax(L, mid) - pre[L - 1] >= 0) {
					r = mid - 1;
					res = mid;
				}
				else l = mid + 1;
			}
			//debug(0, L, R, res);
			dfs(dfs, L + 1, res - 1);
			now++;
			dfs(dfs, res + 1, R);
		}
		else {
			ans.pb({ now,2 });
			int l = L, r = R, res = 0;
			while (l <= r) {
				int mid = l + r >> 1;
				if (stmn.queryMin(L, mid) - pre[L - 1] <= 0) {
					r = mid - 1;
					res = mid;
				}
				else l = mid + 1;
			}
			//debug(1, L, R, res);
			dfs(dfs, L + 1, res - 1);
			now++;
			dfs(dfs, res + 1, R);
		}
		};
	dfs(dfs, 1, n);

	cout << ans.size() << endl;
	for (const var& [x, y] : ans)cout << x << ' ' << y << endl;
	return;
}
